export const longtails: LongTail[] = [
  // ═══ PROBLÈMES FRÉQUENTS ═══
  { slug: "canalisation-bouchee-val-doise", category: "probleme", h1: "Canalisation Bouchée dans le Val d'Oise", metaTitle: "Canalisation Bouchée Val d'Oise (95) — Intervention Rapide", metaDesc: "Votre canalisation est bouchée dans le Val d'Oise ? Nos artisans interviennent sous 1h pour déboucher vos canalisations par hydrocurage ou furet. Devis gratuit.", intro: "Une canalisation bouchée peut rapidement dégénérer en refoulement d'eaux usées si elle n'est pas traitée rapidement.", content: "Nos artisans canalisateurs du Val d'Oise (95) utilisent des techniques professionnelles pour déboucher vos canalisations : hydrocurage haute pression (jusqu'à 350 bars), furet électrique rotatif, et injection d'eau chaude sous pression. Nous intervenons sur tous types de bouchons : accumulation de calcaire, intrusion de racines, dépôts de graisse, objets coincés. Chaque intervention inclut un diagnostic caméra pour identifier la cause exacte du bouchon et prévenir les récidives. Intervention 7j/7, devis gratuit sur place." },
  { slug: "fuite-canalisation-enterree", category: "probleme", h1: "Fuite sur Canalisation Enterrée — Détection et Réparation", metaTitle: "Fuite Canalisation Enterrée Val d'Oise — Détection Sans Casser", metaDesc: "Fuite sur canalisation enterrée dans le Val d'Oise ? Détection par écoute acoustique et gaz traceur, réparation ciblée sans tout casser. Devis gratuit.", intro: "Une fuite sur une canalisation enterrée est souvent invisible en surface mais peut causer des dégâts considérables : affaissement de terrain, infiltrations, surconsommation d'eau.", content: "Nos techniciens utilisent des méthodes de détection non destructives : écoute acoustique au sol (les fuites émettent un bruit caractéristique captable par des capteurs piézoélectriques), corrélation (mesure du temps de propagation du bruit entre deux points), et injection de gaz traceur hydrogène-azote (H2/N2) pour les micro-fuites indétectables autrement. Une fois la fuite localisée au centimètre près, nous effectuons une réparation ciblée : manchon de réparation, collier de prise en charge, ou remplacement du tronçon endommagé. Conforme aux DTU 60.1 et DTU 60.11." },
  { slug: "canalisation-cassee-que-faire", category: "probleme", h1: "Canalisation Cassée : Que Faire en Urgence ?", metaTitle: "Canalisation Cassée — Intervention d'Urgence Val d'Oise (95)", metaDesc: "Canalisation cassée dans le Val d'Oise ? Fermez l'arrivée d'eau et appelez-nous. Intervention sous 1h, remplacement express, garantie décennale.", intro: "Une canalisation cassée nécessite une intervention immédiate pour limiter les dégâts des eaux et prévenir tout risque sanitaire.", content: "Les premiers réflexes : coupez l'arrivée d'eau au compteur, prévenez votre assurance habitation, et appelez un artisan canalisateur. Nos équipes du Val d'Oise interviennent en moins d'1 heure pour sécuriser la zone et effectuer un remplacement express. Nous traitons tous les cas : canalisation écrasée par un engin, tuyau fissuré par le gel, canalisation rompue par mouvement de terrain argileux (fréquent en Val d'Oise). Remplacement en PVC CR8/CR16 ou PEHD PE100, essai d'étanchéité sous pression, remise en état du terrain." },
  { slug: "refoulement-eaux-usees", category: "probleme", h1: "Refoulement d'Eaux Usées — Intervention d'Urgence", metaTitle: "Refoulement Eaux Usées Val d'Oise — Débouchage Urgent 7j/7", metaDesc: "Refoulement d'eaux usées dans votre maison ? Nos artisans du Val d'Oise interviennent en urgence pour déboucher et nettoyer. Disponible 7j/7.", intro: "Le refoulement d'eaux usées est une urgence sanitaire : risque de contamination bactérienne, odeurs nauséabondes, dégâts matériels importants.", content: "Les causes principales de refoulement sont : canalisation principale bouchée (racines, calcaire, graisse), contre-pente sur le réseau d'évacuation, effondrement partiel de la canalisation, ou saturation du réseau public lors de fortes pluies. Notre intervention : débouchage par hydrocurage haute pression, inspection caméra pour identifier la cause, et si nécessaire, remplacement du tronçon défaillant. Nous intervenons dans tout le Val d'Oise, y compris les week-ends et jours fériés." },
  { slug: "odeur-egout-maison", category: "probleme", h1: "Odeur d'Égout dans la Maison — Causes et Solutions", metaTitle: "Odeur Égout Maison Val d'Oise — Diagnostic et Réparation", metaDesc: "Odeur d'égout persistante dans votre maison dans le Val d'Oise ? Siphon sec, canalisation fissurée, joint défectueux. Diagnostic et réparation rapide.", intro: "Les odeurs d'égout dans une habitation signalent un dysfonctionnement du réseau d'évacuation qu'il ne faut pas ignorer.", content: "Les causes les plus fréquentes : siphon desséché (la garde d'eau ne joue plus son rôle de barrière anti-odeur), joint défectueux entre la canalisation et le regard, fissure dans le réseau permettant aux gaz de remonter, ou absence de ventilation primaire sur la colonne de chute. Notre diagnostic inclut une inspection caméra complète du réseau, un test fumigène pour localiser les infiltrations de gaz, et la réparation adaptée. Nos artisans du Val d'Oise maîtrisent les normes NF DTU 60.11 relatives à l'assainissement." },
  { slug: "canalisation-racines-arbres", category: "probleme", h1: "Racines d'Arbres dans les Canalisations — Traitement", metaTitle: "Racines dans Canalisation Val d'Oise — Retrait et Protection", metaDesc: "Racines d'arbres infiltrées dans vos canalisations ? Retrait mécanique, traitement anti-racines et remplacement si nécessaire. Val d'Oise (95).", intro: "Les racines d'arbres sont l'une des premières causes de destruction de canalisations enterrées, particulièrement dans les zones pavillonnaires du Val d'Oise.", content: "Les racines s'infiltrent par les joints, les fissures ou les raccords des canalisations à la recherche d'eau et de nutriments. Elles provoquent des bouchons récurrents, des fissures, et à terme la rupture complète du tuyau. Notre traitement : retrait mécanique par furet à lame rotative, hydrocurage pour nettoyer les résidus, inspection caméra pour évaluer l'état résiduel du tuyau, puis selon la gravité : traitement préventif anti-racines, chemisage (gainage intérieur) ou remplacement complet de la canalisation." },
  { slug: "affaissement-canalisation", category: "probleme", h1: "Affaissement de Canalisation — Diagnostic et Réparation", metaTitle: "Affaissement Canalisation Val d'Oise — Diagnostic Caméra + Réparation", metaDesc: "Canalisation affaissée dans le Val d'Oise ? Diagnostic caméra pour évaluer la gravité, puis réparation par chemisage ou remplacement. Devis gratuit.", intro: "L'affaissement de canalisation crée une contre-pente où l'eau stagne, provoquant bouchons à répétition et dégradation accélérée du tuyau.", content: "Les terrains argileux du Val d'Oise (particulièrement à Montmorency, Cormeilles-en-Parisis, Franconville) sont sujets aux mouvements de sol qui déforment les canalisations. Le diagnostic caméra avec mesure de pente permet de localiser précisément la zone affaissée. Solutions : si l'affaissement est léger, un chemisage (gaine souple durcie aux UV) peut renforcer la canalisation in situ. Si l'affaissement est sévère, le remplacement du tronçon avec pose sur lit de sable compacté et remblai contrôlé est nécessaire." },
  { slug: "canalisation-percee-jardin", category: "probleme", h1: "Canalisation Percée dans le Jardin — Réparation Express", metaTitle: "Canalisation Percée Jardin Val d'Oise — Réparation Rapide", metaDesc: "Canalisation percée dans votre jardin dans le Val d'Oise ? Détection, réparation ou remplacement rapide. Remise en état pelouse incluse.", intro: "Une canalisation percée dans le jardin se manifeste souvent par une zone anormalement humide, de l'herbe plus verte à un endroit, ou un affaissement du terrain.", content: "Nos artisans du Val d'Oise localisent la fuite par détection acoustique ou gaz traceur, puis creusent de manière ciblée pour accéder au tuyau endommagé. Réparation par manchon ou remplacement du tronçon en PVC CR8 ou PEHD. La remise en état complète du jardin est incluse : remblaiement, compactage, remise en place de la terre végétale et de la pelouse. Intervention possible même en terrain difficile (argileux, rocheux, avec nappe phréatique haute)." },
  { slug: "compteur-eau-qui-tourne-tout-seul", category: "probleme", h1: "Compteur d'Eau qui Tourne Tout Seul — Fuite Cachée ?", metaTitle: "Compteur Eau Tourne Seul Val d'Oise — Détection Fuite Cachée", metaDesc: "Votre compteur d'eau tourne alors que tous les robinets sont fermés ? Probable fuite cachée sur canalisation. Détection et réparation Val d'Oise.", intro: "Un compteur qui tourne alors que tous les points d'eau sont fermés est le signe quasi certain d'une fuite sur votre réseau privatif.", content: "Test simple : fermez tous les robinets et appareils utilisant de l'eau, relevez le compteur, attendez 2 heures et relevez à nouveau. Si le compteur a tourné, vous avez une fuite. Nos techniciens du Val d'Oise utilisent la détection acoustique et la corrélation pour localiser la fuite sans casser. Réparation ciblée et rapide. Important : la loi Warsmann vous protège en cas de surconsommation due à une fuite — nous vous fournissons l'attestation de réparation nécessaire pour obtenir un plafonnement de votre facture d'eau." },
  { slug: "infiltration-eau-sous-sol", category: "probleme", h1: "Infiltration d'Eau dans le Sous-Sol — Causes et Solutions", metaTitle: "Infiltration Eau Sous-Sol Val d'Oise — Diagnostic et Traitement", metaDesc: "Infiltration d'eau dans votre sous-sol ou cave dans le Val d'Oise ? Diagnostic des causes (canalisation, nappe, ruissellement) et traitement durable.", intro: "Les infiltrations d'eau en sous-sol peuvent provenir d'une canalisation défectueuse, d'une remontée de nappe phréatique, ou d'un défaut d'étanchéité.", content: "Dans le Val d'Oise, les nappes phréatiques hautes (notamment à Bezons, Herblay, Saint-Ouen-l'Aumône en bord de Seine/Oise) amplifient les risques d'infiltration. Notre diagnostic différentiel identifie l'origine exacte : test de coloration pour vérifier si l'eau provient du réseau d'évacuation, mesure piézométrique pour évaluer le niveau de nappe, inspection caméra des canalisations environnantes. Solutions : réparation ou remplacement de la canalisation fautive, drainage périphérique, cuvelage du sous-sol, installation de pompe de relevage." },

  // ═══ SERVICES SPÉCIFIQUES ═══
  { slug: "remplacement-canalisation-fonte", category: "materiau", h1: "Remplacement de Canalisation en Fonte — Val d'Oise", metaTitle: "Remplacement Canalisation Fonte Val d'Oise — PVC ou PEHD", metaDesc: "Remplacement de vos anciennes canalisations en fonte par du PVC ou PEHD dans le Val d'Oise. Artisans spécialisés, garantie décennale, devis gratuit.", intro: "Les canalisations en fonte, très répandues dans les immeubles et maisons d'avant 1970 du Val d'Oise, sont sujettes à la corrosion et aux fissures après 50 ans.", content: "La fonte ductile ou grise se corrode de l'intérieur par les eaux usées acides, créant des dépôts qui réduisent le diamètre utile et provoquent des bouchons. Le remplacement par du PVC CR8 (réseaux gravitaires) ou PEHD PE100 (réseaux sous pression) offre une durée de vie de 50+ ans, une résistance à la corrosion totale, et un coût nettement inférieur. Nos artisans maîtrisent la dépose de fonte (sciage, extraction) et la pose aux normes NF EN 1401 (PVC) et NF EN 12201 (PEHD)." },
  { slug: "remplacement-canalisation-pvc", category: "materiau", h1: "Remplacement de Canalisation PVC — Val d'Oise", metaTitle: "Remplacement Canalisation PVC Val d'Oise — CR8 CR16 aux Normes", metaDesc: "Remplacement de canalisation PVC dans le Val d'Oise. Tubes CR8/CR16 aux normes NF EN 1401. Pose en tranchée, raccordement, essai étanchéité.", intro: "Même les canalisations PVC des années 80-90 peuvent nécessiter un remplacement après 30-40 ans, surtout si elles ont subi des mouvements de terrain.", content: "Le PVC CR8 (classe de rigidité 8 kN/m²) convient aux réseaux d'assainissement gravitaire à faible profondeur. Le PVC CR16 est recommandé pour les profondeurs supérieures à 2 mètres ou sous voirie. Nos artisans du Val d'Oise posent les canalisations sur lit de sable (10 cm minimum), avec enrobage latéral et remblai en matériau sélectionné compacté par couches de 20 cm. Chaque raccordement est collé ou à joint élastomère selon les normes NF EN 1401-1." },
  { slug: "remplacement-canalisation-plomb", category: "materiau", h1: "Remplacement de Canalisation en Plomb — Mise en Conformité", metaTitle: "Remplacement Canalisation Plomb Val d'Oise — Mise aux Normes", metaDesc: "Canalisations en plomb dans le Val d'Oise ? Remplacement obligatoire pour mise en conformité sanitaire. Artisans certifiés, devis gratuit.", intro: "Les canalisations en plomb sont interdites depuis 1995 en raison du risque de saturnisme. Si votre logement en possède encore, le remplacement est fortement recommandé.", content: "Le plomb libère des particules toxiques dans l'eau potable, particulièrement dangereuses pour les enfants et les femmes enceintes. Dans le Val d'Oise, de nombreux logements construits avant 1950 possèdent encore des branchements en plomb. Le remplacement se fait par du cuivre (alimentation eau potable), du PER (polyéthylène réticulé) ou du multicouche. Nos artisans certifiés effectuent le remplacement complet avec raccordement au réseau public et attestation de conformité." },
  { slug: "chemisage-canalisation-sans-tranchee", category: "technique", h1: "Chemisage de Canalisation Sans Tranchée — Réhabilitation", metaTitle: "Chemisage Canalisation Sans Tranchée Val d'Oise — Gainage In Situ", metaDesc: "Réhabilitation de canalisation par chemisage (gainage) sans tranchée dans le Val d'Oise. Pas de terrassement, moins cher, durée de vie 50 ans.", intro: "Le chemisage permet de réparer une canalisation endommagée sans la déterrer, en insérant une gaine souple imprégnée de résine qui durcit en place.", content: "La technique de chemisage (ou tubage) consiste à insérer dans la canalisation existante une gaine en feutre ou fibre de verre imprégnée de résine époxy ou polyester. La gaine est gonflée contre les parois puis durcie par polymérisation UV ou thermique. Le résultat est un tuyau neuf à l'intérieur de l'ancien, étanche, lisse et résistant pour 50+ ans. Avantages : pas de terrassement (préservation du jardin, de la terrasse, de l'allée), intervention rapide (1 journée), coût réduit de 30 à 50% par rapport au remplacement classique." },
  { slug: "hydrocurage-canalisation", category: "technique", h1: "Hydrocurage de Canalisation — Nettoyage Haute Pression", metaTitle: "Hydrocurage Canalisation Val d'Oise — Nettoyage Haute Pression Pro", metaDesc: "Hydrocurage professionnel de vos canalisations dans le Val d'Oise. Jet haute pression jusqu'à 350 bars. Élimine calcaire, racines, graisses.", intro: "L'hydrocurage est la méthode professionnelle la plus efficace pour nettoyer et déboucher les canalisations de tous diamètres.", content: "Notre camion hydrocureur projette de l'eau à haute pression (150 à 350 bars) via une buse rotative qui nettoie les parois internes de la canalisation. Cette technique élimine tous les dépôts : calcaire, tartre, graisses, racines, résidus organiques. L'hydrocurage est recommandé en curatif (débouchage) et en préventif (entretien annuel). Nous intervenons sur canalisations de Ø50 mm à Ø400 mm, en PVC, fonte, grès ou béton." },
  { slug: "inspection-camera-canalisation", category: "service", h1: "Inspection Caméra de Canalisation — Diagnostic Vidéo HD", metaTitle: "Inspection Caméra Canalisation Val d'Oise — Diagnostic Vidéo Pro", metaDesc: "Inspection caméra de vos canalisations dans le Val d'Oise. Caméra HD avec localisation GPS. Rapport vidéo détaillé. À partir de 200€.", intro: "L'inspection par caméra endoscopique est le seul moyen fiable de connaître l'état réel de vos canalisations sans les déterrer.", content: "Notre caméra motorisée (diamètre 25 à 50 mm) parcourt l'intérieur de la canalisation en enregistrant des images HD. Un compteur métrique mesure la distance depuis le point d'entrée, et un émetteur radio permet de localiser la caméra en surface avec une précision de 10 cm. Le rapport d'inspection comprend : vidéo complète, captures d'écran des anomalies détectées, localisation GPS de chaque défaut, et recommandations techniques. Cette inspection est indispensable avant un achat immobilier, pour un constat de conformité, ou pour diagnostiquer des problèmes récurrents." },
  { slug: "detection-fuite-non-destructive", category: "technique", h1: "Détection de Fuite Non Destructive — Techniques Avancées", metaTitle: "Détection Fuite Non Destructive Val d'Oise — Sans Casser", metaDesc: "Détection de fuite sans destruction dans le Val d'Oise. Écoute acoustique, corrélation, gaz traceur. Localisation au centimètre près.", intro: "Les techniques modernes de détection de fuite permettent de localiser précisément un défaut d'étanchéité sans aucune démolition.", content: "Trois méthodes complémentaires : 1) Écoute acoustique au sol — un capteur piézoélectrique amplifie le bruit de la fuite à travers le sol. 2) Corrélation — deux capteurs placés de part et d'autre de la zone suspecte mesurent le temps de propagation du bruit, permettant un calcul mathématique de la position exacte. 3) Gaz traceur H2/N2 — un mélange hydrogène-azote est injecté dans la canalisation ; l'hydrogène, plus léger que l'air, remonte à travers le sol et est détecté en surface par un capteur spécifique. Précision : ±10 cm." },
  { slug: "raccordement-tout-a-legout", category: "service", h1: "Raccordement au Tout-à-l'Égout — Val d'Oise", metaTitle: "Raccordement Tout-à-l'Égout Val d'Oise — Obligatoire et Subventionné", metaDesc: "Raccordement au tout-à-l'égout dans le Val d'Oise. Obligation légale sous 2 ans. Nos artisans gèrent le terrassement, la pose et le raccordement.", intro: "Le raccordement au réseau public d'assainissement collectif est obligatoire dans un délai de 2 ans après la mise en service du réseau dans votre rue.", content: "Le raccordement comprend : réalisation de la tranchée depuis votre habitation jusqu'au regard de branchement public, pose de la canalisation en PVC CR8 diamètre 125 ou 160 mm avec pente minimum de 1%, création ou mise en conformité du regard de façade, raccordement au collecteur public avec autorisation de la commune. Nos artisans du Val d'Oise gèrent l'ensemble du chantier, y compris les démarches administratives auprès du SIARE ou du syndicat d'assainissement local." },

  // ═══ PRIX ET TARIFS ═══
  { slug: "prix-remplacement-canalisation", category: "prix", h1: "Prix Remplacement de Canalisation — Tarifs 2026", metaTitle: "Prix Remplacement Canalisation Val d'Oise — Tarifs Détaillés 2026", metaDesc: "Combien coûte un remplacement de canalisation dans le Val d'Oise ? De 80 à 200€/ml selon le matériau et la profondeur. Devis gratuit détaillé.", intro: "Le prix d'un remplacement de canalisation dépend de plusieurs facteurs : longueur, profondeur, matériau, accessibilité et nature du terrain.", content: "Fourchettes de prix indicatives 2026 dans le Val d'Oise : Terrassement en tranchée : 30 à 80€/ml selon la profondeur. Fourniture PVC CR8 Ø125 : 8 à 15€/ml. Fourniture PEHD PE100 Ø110 : 12 à 25€/ml. Pose et raccordement : 40 à 80€/ml. Remise en état terrain : 20 à 60€/ml. Total estimatif : 80 à 200€/ml tout compris. Un remplacement de 10 mètres linéaires coûte en moyenne entre 1 500 et 3 000€ TTC. Nos devis détaillent chaque poste : terrassement, fourniture, pose, raccordement, remise en état." },
  { slug: "prix-reparation-fuite-canalisation", category: "prix", h1: "Prix Réparation de Fuite sur Canalisation — Tarifs", metaTitle: "Prix Réparation Fuite Canalisation Val d'Oise — Tarifs 2026", metaDesc: "Tarifs réparation de fuite sur canalisation dans le Val d'Oise. À partir de 150€. Détection + réparation incluse. Devis gratuit.", intro: "Le coût d'une réparation de fuite dépend principalement de la technique de détection nécessaire et du type de réparation.", content: "Tarifs indicatifs 2026 : Détection de fuite par écoute acoustique : 150 à 300€. Détection par gaz traceur : 250 à 450€. Réparation par manchon/collier : 150 à 400€. Remplacement tronçon (1 à 3 ml) : 300 à 800€. Le forfait détection + réparation démarre à 150€ pour les cas simples (fuite visible, joint défectueux) et peut atteindre 1 000 à 1 500€ pour les fuites complexes (canalisation enterrée profonde, accès difficile)." },
  { slug: "prix-diagnostic-camera-canalisation", category: "prix", h1: "Prix Diagnostic Caméra Canalisation — Tarifs", metaTitle: "Prix Inspection Caméra Canalisation Val d'Oise — À Partir de 200€", metaDesc: "Combien coûte une inspection caméra de canalisation ? À partir de 200€ dans le Val d'Oise. Rapport vidéo HD + localisation GPS inclus.", intro: "L'inspection caméra est un investissement rentable : elle permet d'éviter des travaux inutiles en ciblant précisément le problème.", content: "Tarifs indicatifs 2026 : Inspection caméra standard (jusqu'à 30 ml) : 200 à 350€. Inspection avec localisation GPS des anomalies : 300 à 500€. Rapport vidéo détaillé avec recommandations : inclus. L'inspection est souvent amortie dès la première intervention car elle évite de creuser au mauvais endroit. Cas où l'inspection est particulièrement recommandée : avant un achat immobilier, en cas de bouchons récurrents, avant des travaux de rénovation, pour un constat de conformité d'assainissement." },
  { slug: "cout-raccordement-tout-a-legout", category: "prix", h1: "Coût Raccordement Tout-à-l'Égout — Estimation", metaTitle: "Coût Raccordement Tout-à-l'Égout Val d'Oise — 2 000 à 8 000€", metaDesc: "Estimation du coût de raccordement au tout-à-l'égout dans le Val d'Oise. Entre 2 000 et 8 000€ selon la distance. Subventions possibles.", intro: "Le raccordement au tout-à-l'égout est un investissement obligatoire mais qui valorise votre bien immobilier.", content: "Estimation des coûts 2026 dans le Val d'Oise : Raccordement court (moins de 10 ml) : 2 000 à 4 000€. Raccordement moyen (10 à 20 ml) : 4 000 à 6 000€. Raccordement long ou complexe (plus de 20 ml, traversée de voirie) : 6 000 à 10 000€. La participation pour raccordement au réseau (PFAC) varie selon les communes du Val d'Oise. Certaines communes proposent des subventions ou des facilités de paiement. Nos artisans vous accompagnent dans les démarches administratives." },

  // ═══ URGENCES SPÉCIFIQUES ═══
  { slug: "urgence-canalisation-nuit-weekend", category: "urgence", h1: "Urgence Canalisation Nuit et Week-end — Val d'Oise", metaTitle: "Urgence Canalisation Nuit Week-end Val d'Oise — Intervention 7j/7", metaDesc: "Problème de canalisation la nuit ou le week-end dans le Val d'Oise ? Nos artisans interviennent 7j/7 de 8h à 20h. Pas de majoration.", intro: "Les urgences de canalisation n'attendent pas les jours ouvrables. Notre consortium d'artisans assure une permanence 7 jours sur 7.", content: "Nous intervenons de 8h à 20h tous les jours, y compris les samedis, dimanches et jours fériés, sans aucune majoration de prix. Nos artisans du Val d'Oise sont répartis sur l'ensemble du département pour garantir un temps d'intervention court quel que soit le jour. Types d'urgences les plus fréquentes : fuite active avec dégât des eaux, refoulement d'eaux usées, canalisation cassée suite à des travaux, rupture de canalisation par le gel en hiver." },
  { slug: "degat-des-eaux-canalisation", category: "urgence", h1: "Dégât des Eaux lié à une Canalisation — Que Faire ?", metaTitle: "Dégât des Eaux Canalisation Val d'Oise — Intervention + Assurance", metaDesc: "Dégât des eaux causé par une canalisation dans le Val d'Oise ? Intervention urgente + aide aux démarches assurance. Agréé AXA, Allianz, MAAF.", intro: "Un dégât des eaux causé par une canalisation défaillante nécessite une intervention rapide ET une bonne gestion du dossier assurance.", content: "Étapes à suivre : 1) Coupez l'eau au compteur, 2) Prenez des photos des dégâts, 3) Appelez votre assurance pour déclarer le sinistre, 4) Appelez-nous pour l'intervention technique. Nos artisans sont agréés par les principales compagnies d'assurance (AXA, Allianz, MAAF, GMF, MACIF, Groupama, MMA). Nous fournissons un rapport d'intervention détaillé et une facture conforme aux exigences de votre assureur pour faciliter votre remboursement." },
  { slug: "canalisation-gelee-hiver", category: "urgence", h1: "Canalisation Gelée en Hiver — Dégel et Protection", metaTitle: "Canalisation Gelée Val d'Oise — Dégel Urgent et Isolation", metaDesc: "Canalisation gelée dans le Val d'Oise ? Dégel professionnel sans endommager le tuyau + isolation pour éviter les récidives.", intro: "Le gel est l'ennemi n°1 des canalisations en hiver : l'eau se dilate de 9% en gelant, ce qui peut fissurer ou éclater les tuyaux.", content: "En Val d'Oise, les hivers peuvent être rigoureux avec des températures descendant sous -5°C. Les canalisations les plus exposées sont celles en extérieur, dans les vides sanitaires non chauffés, ou les branchements peu enterrés. Notre intervention : dégel progressif par chaleur contrôlée (jamais de flamme directe qui risquerait d'endommager le tuyau), vérification de l'intégrité après dégel, et mise en place de protection : gaine isolante, câble chauffant thermostaté, ou approfondissement de la canalisation sous la profondeur de gel (60 cm en Val d'Oise)." },

  // ═══ PAR VILLE (top 15 villes) ═══
  { slug: "remplacement-canalisation-argenteuil", category: "ville", h1: "Remplacement de Canalisation à Argenteuil (95100)", metaTitle: "Remplacement Canalisation Argenteuil (95100) — Artisan Local", metaDesc: "Remplacement de canalisation à Argenteuil (95100). Plus grande ville du Val d'Oise, réseaux anciens centre-ville. Artisan local, devis gratuit.", intro: "Argenteuil, plus grande ville du Val d'Oise avec 110 000 habitants, possède un parc de canalisations varié : fonte ancienne en centre-ville, PVC des années 70-80 dans les grands ensembles.", content: "Nos artisans connaissent les spécificités du réseau argenteuillais : canalisations en fonte vieillissantes du centre historique, réseaux collectifs des grands ensembles (Val-Nord, Val-Sud), terrain alluvial en bord de Seine avec nappe haute. Nous intervenons dans tous les quartiers : Centre-ville, Orgemont, Val-Notre-Dame, Joliot-Curie, Champagne. Intervention sous 45 minutes depuis notre base." },
  { slug: "remplacement-canalisation-cergy", category: "ville", h1: "Remplacement de Canalisation à Cergy (95000)", metaTitle: "Remplacement Canalisation Cergy (95000) — Intervention Rapide", metaDesc: "Remplacement de canalisation à Cergy (95000). Ville nouvelle, réseaux 70-80 à rénover. Artisan canalisateur local, garantie décennale.", intro: "Cergy, cœur de l'agglomération de Cergy-Pontoise, possède des infrastructures datant des années 70-80 qui nécessitent aujourd'hui des remplacements.", content: "Les quartiers de Cergy (Préfecture, Grand Centre, Hauts-de-Cergy, Axe Majeur) ont été construits entre 1970 et 1990. Les canalisations PVC de cette époque arrivent en fin de vie après 40-50 ans d'utilisation. Nos artisans interviennent régulièrement à Cergy pour remplacer ces réseaux vieillissants par des matériaux modernes aux normes NF EN 1401. Intervention rapide dans toute l'agglomération cergyssoise." },
  { slug: "reparation-fuite-pontoise", category: "ville", h1: "Réparation de Fuite à Pontoise (95000)", metaTitle: "Réparation Fuite Pontoise (95000) — Détection et Réparation", metaDesc: "Fuite de canalisation à Pontoise (95000) ? Détection non destructive et réparation rapide. Ville historique, réseaux anciens. Devis gratuit.", intro: "Pontoise, ville historique et préfecture du Val d'Oise, possède un centre médiéval avec des réseaux d'assainissement parmi les plus anciens du département.", content: "Le centre historique de Pontoise (quartier de la cathédrale, rue de la Coutellerie, place du Petit Martroy) abrite des canalisations centenaires en grès ou en fonte. Les terrains instables près de l'Oise ajoutent une contrainte supplémentaire. Nos techniciens maîtrisent la détection de fuite en milieu urbain dense, où l'accessibilité est limitée et la précision essentielle pour éviter de creuser dans la voie publique." },
  { slug: "diagnostic-camera-sarcelles", category: "ville", h1: "Diagnostic Caméra Canalisation à Sarcelles (95200)", metaTitle: "Diagnostic Caméra Canalisation Sarcelles (95200) — Inspection HD", metaDesc: "Inspection caméra de canalisation à Sarcelles (95200). Grand ensemble, réseaux collectifs des années 60. Rapport vidéo détaillé, devis gratuit.", intro: "Sarcelles, avec ses grands ensembles des années 60, possède des réseaux collectifs qui nécessitent un suivi régulier par inspection caméra.", content: "Les canalisations des barres et tours de Sarcelles (quartier des Lochères, Chardonnerettes, Rosiers) sont souvent des réseaux collectifs en fonte de gros diamètre (200 à 300 mm). L'inspection caméra permet de planifier les remplacements de manière préventive plutôt que d'attendre la panne. Notre caméra motorisée s'adapte aux gros diamètres et fournit un rapport détaillé exploitable par les syndics de copropriété." },
  { slug: "remplacement-canalisation-enghien-les-bains", category: "ville", h1: "Remplacement de Canalisation à Enghien-les-Bains (95880)", metaTitle: "Remplacement Canalisation Enghien-les-Bains (95880) — Artisan Local", metaDesc: "Remplacement de canalisation à Enghien-les-Bains (95880). Ville thermale, contraintes eaux souterraines et lac. Expertise locale.", intro: "Enghien-les-Bains, unique ville thermale d'Île-de-France, présente des contraintes spécifiques liées aux eaux souterraines et à la proximité du lac.", content: "Le sous-sol d'Enghien est riche en eaux sulfureuses qui accélèrent la corrosion des canalisations métalliques. La nappe phréatique haute rend les travaux de terrassement plus complexes (pompage nécessaire). Nos artisans utilisent exclusivement des matériaux résistants aux eaux agressives (PVC et PEHD) et maîtrisent les techniques de pose en terrain gorgé d'eau." },
  { slug: "reparation-fuite-franconville", category: "ville", h1: "Réparation de Fuite à Franconville (95130)", metaTitle: "Réparation Fuite Franconville (95130) — Détection Sans Casser", metaDesc: "Fuite de canalisation à Franconville (95130) ? Zone pavillonnaire, terrain argileux. Détection précise et réparation rapide. Devis gratuit.", intro: "Franconville, ville pavillonnaire du Val d'Oise, est située sur un terrain argileux qui provoque des mouvements de sol endommageant les canalisations.", content: "Le retrait-gonflement des argiles est un phénomène bien connu à Franconville : en période de sécheresse, le sol se rétracte et peut fissurer les canalisations ; en période humide, il gonfle et exerce une pression sur les tuyaux. Nos artisans connaissent cette problématique locale et utilisent des techniques de pose adaptées : lit de sable renforcé, joints souples, canalisations en PEHD (plus flexibles que le PVC)." },
  { slug: "canalisation-urgence-ermont", category: "ville", h1: "Canalisation en Urgence à Ermont (95120)", metaTitle: "Canalisation Urgence Ermont (95120) — Intervention Sous 1h", metaDesc: "Urgence canalisation à Ermont (95120) ? Fuite, bouchon, refoulement. Nos artisans interviennent sous 1h. 7j/7, devis gratuit.", intro: "Ermont, au cœur de la vallée de Montmorency, dispose de canalisations des années 50-70 qui nécessitent des remplacements progressifs.", content: "La zone résidentielle dense d'Ermont (quartiers de la gare, Cernay, boulevard Léon Blum) présente des contraintes d'accessibilité pour les travaux de canalisation. Nos artisans maîtrisent les interventions en milieu urbain serré : mini-pelles, ouverture ciblée de tranchées, coordination avec les services de voirie. Intervention sous 1 heure depuis notre base du Val d'Oise." },
  { slug: "remplacement-canalisation-goussainville", category: "ville", h1: "Remplacement de Canalisation à Goussainville (95190)", metaTitle: "Remplacement Canalisation Goussainville (95190) — Devis Gratuit", metaDesc: "Remplacement de canalisation à Goussainville (95190). Réseaux mixtes ancien village et zones d'activités. Artisan local, garantie décennale.", intro: "Goussainville présente un tissu urbain mixte entre l'ancien village et les zones d'activités, avec des réseaux de canalisations de différentes époques.", content: "Le vieux Goussainville possède des canalisations très anciennes (certaines en grès), tandis que la ville nouvelle des années 60-70 a des réseaux PVC vieillissants. Les zones d'activités (ZAC des Tulipes, zone aéroportuaire) ont des besoins spécifiques en canalisation industrielle. Nos artisans interviennent sur tous types de réseaux, du particulier au professionnel." },
  { slug: "reparation-canalisation-taverny", category: "ville", h1: "Réparation de Canalisation à Taverny (95150)", metaTitle: "Réparation Canalisation Taverny (95150) — Artisan Canalisateur", metaDesc: "Réparation de canalisation à Taverny (95150). Entre forêt et zone urbaine, problématiques racines et calcaire. Intervention rapide.", intro: "Taverny, située entre la forêt de Montmorency et la plaine, cumule les problématiques de racines intrusives et de terrain calcaire.", content: "La proximité de la forêt de Montmorency expose les canalisations de Taverny à l'intrusion de racines, particulièrement les réseaux en fonte ou grès dont les joints se dégradent avec le temps. Le terrain calcaire peut aussi provoquer des dépôts importants dans les tuyaux. Nos artisans proposent un traitement complet : retrait des racines, nettoyage anti-calcaire par hydrocurage, et si nécessaire remplacement par du PVC résistant aux racines." },
  { slug: "diagnostic-camera-bezons", category: "ville", h1: "Diagnostic Caméra Canalisation à Bezons (95870)", metaTitle: "Diagnostic Caméra Canalisation Bezons (95870) — Inspection Pro", metaDesc: "Inspection caméra de canalisation à Bezons (95870). Bord de Seine, nappe haute. Rapport vidéo détaillé avec localisation GPS.", intro: "Bezons, en bord de Seine, est soumise à des nappes phréatiques hautes qui fragilisent les canalisations enterrées.", content: "Les canalisations de Bezons sont soumises à une humidité permanente due à la proximité de la Seine et à la nappe phréatique élevée. Cette humidité accélère la corrosion des canalisations métalliques et peut provoquer des infiltrations dans les regards. L'inspection caméra permet de détecter les points faibles avant qu'ils ne deviennent des urgences. Nos techniciens connaissent les contraintes spécifiques du bord de Seine." },

  // ═══ QUESTIONS SPÉCIFIQUES (People Also Ask) ═══
  { slug: "qui-paye-remplacement-canalisation", category: "prix", h1: "Qui Paye le Remplacement de Canalisation ? Propriétaire ou Locataire ?", metaTitle: "Qui Paye Remplacement Canalisation — Propriétaire ou Locataire ?", metaDesc: "Remplacement de canalisation : qui paye ? Le propriétaire pour les travaux lourds, le locataire pour l'entretien courant. Explications détaillées.", intro: "La question de la prise en charge des travaux de canalisation oppose souvent propriétaires et locataires. Voici les règles.", content: "Selon la loi du 6 juillet 1989 et le décret du 26 août 1987 : le locataire est responsable de l'entretien courant (débouchage simple, remplacement de joints). Le propriétaire est responsable des travaux lourds : remplacement de canalisation, réparation structurelle, mise en conformité. En copropriété, les canalisations sont parties communes si elles desservent plusieurs lots. Les travaux sur parties communes sont votés en assemblée générale et financés par les copropriétaires. Notre attestation de travaux facilite la répartition des charges." },
  { slug: "assurance-prend-en-charge-canalisation", category: "prix", h1: "L'Assurance Prend-elle en Charge la Canalisation ?", metaTitle: "Assurance et Canalisation — Prise en Charge, Conditions, Démarches", metaDesc: "Votre assurance habitation prend-elle en charge les travaux de canalisation ? Conditions, démarches et rôle de l'artisan agréé. Val d'Oise.", intro: "L'assurance habitation peut prendre en charge tout ou partie des travaux de canalisation, mais sous certaines conditions.", content: "La garantie dégât des eaux de votre assurance habitation couvre généralement : la recherche de fuite (frais de détection), la réparation de la fuite elle-même, et les dommages causés par la fuite (plafonds, murs, sols). En revanche, le remplacement préventif d'une canalisation vétuste n'est pas couvert. Pour être indemnisé : déclarez le sinistre sous 5 jours ouvrés, conservez les factures et photos, faites intervenir un artisan agréé. Nous sommes agréés par AXA, Allianz, MAAF, GMF, MACIF, Matmut, Groupama, MMA — nos factures sont acceptées directement par ces assureurs." },
  { slug: "duree-vie-canalisation", category: "service", h1: "Quelle est la Durée de Vie d'une Canalisation ?", metaTitle: "Durée de Vie Canalisation — Fonte, PVC, PEHD, Cuivre, Plomb", metaDesc: "Durée de vie des canalisations selon le matériau : fonte 50-100 ans, PVC 50 ans, PEHD 50 ans, cuivre 50 ans, plomb à remplacer. Guide complet.", intro: "La durée de vie d'une canalisation dépend du matériau, de la qualité de pose, de la nature du sol et de l'entretien.", content: "Durées de vie moyennes : Fonte ductile : 80 à 100 ans (mais la fonte grise ancienne se corrode après 50 ans). PVC : 50 ans (mais les premiers PVC des années 70 peuvent se fragiliser). PEHD : 50 à 100 ans (le matériau le plus durable aujourd'hui). Cuivre : 50 ans (corrosion possible en eau agressive). Plomb : à remplacer immédiatement (interdit depuis 1995). Grès : 100+ ans (mais joints très fragiles). En Val d'Oise, les canalisations en fonte des centres-villes historiques et les PVC des années 70-80 arrivent en fin de vie." },
  { slug: "canalisation-copropriete-qui-paye", category: "prix", h1: "Canalisation en Copropriété — Qui Paye les Travaux ?", metaTitle: "Canalisation Copropriété — Parties Communes ou Privatives ?", metaDesc: "Travaux de canalisation en copropriété : qui paye ? Distinction parties communes (colonnes) et parties privatives (raccordements). Guide.", intro: "En copropriété, la distinction entre parties communes et parties privatives détermine qui finance les travaux de canalisation.", content: "Règle générale : les colonnes d'évacuation verticales (colonnes de chute) sont des parties communes — les travaux sont votés en AG et financés par tous les copropriétaires au prorata des tantièmes. Les canalisations horizontales situées dans un lot privatif (raccordements entre les appareils sanitaires et la colonne) sont à la charge du copropriétaire concerné. Exception : si un dégât est causé par la partie commune (colonne fissurée), le syndicat de copropriété est responsable même des dommages dans les parties privatives." },
  { slug: "obligation-raccordement-assainissement", category: "service", h1: "Obligation de Raccordement à l'Assainissement Collectif", metaTitle: "Obligation Raccordement Assainissement Val d'Oise — Délais et Sanctions", metaDesc: "Raccordement à l'assainissement collectif : obligation légale sous 2 ans dans le Val d'Oise. Délais, sanctions, aides financières possibles.", intro: "Le Code de la santé publique (article L1331-1) impose le raccordement au réseau public d'assainissement collectif dans un délai de 2 ans.", content: "Si votre rue est desservie par le réseau d'assainissement collectif, vous avez l'obligation de vous y raccorder sous 2 ans. Passé ce délai, la commune peut : doubler le montant de la redevance d'assainissement, réaliser d'office les travaux à vos frais, ou appliquer une astreinte journalière. En Val d'Oise, les syndicats d'assainissement (SIARE, SIAAP) proposent parfois des aides financières ou des facilités de paiement. Nos artisans réalisent les travaux de raccordement complets : tranchée, pose, raccordement, remise en état." },

  // ═══ LONG-TAILS COMPLÉMENTAIRES ═══
  { slug: "remplacement-canalisation-eau-potable", category: "service", h1: "Remplacement de Canalisation d'Eau Potable", metaTitle: "Remplacement Canalisation Eau Potable Val d'Oise — PEHD Alimentaire", metaDesc: "Remplacement de canalisation d'eau potable dans le Val d'Oise. PEHD alimentaire, cuivre ou PER. Conforme ARS, devis gratuit.", intro: "Le remplacement d'une canalisation d'eau potable exige des matériaux conformes aux normes sanitaires et un savoir-faire spécifique.", content: "Les canalisations d'eau potable doivent être en matériau alimentaire certifié ACS (Attestation de Conformité Sanitaire) : PEHD PE100 bleu (norme NF EN 12201), cuivre (NF EN 1057), ou PER (polyéthylène réticulé). Les canalisations en plomb doivent être impérativement remplacées. Nos artisans du Val d'Oise effectuent le remplacement du branchement privatif (entre le compteur et l'habitation), avec rinçage et désinfection du réseau avant remise en service." },
  { slug: "remplacement-canalisation-eaux-usees", category: "service", h1: "Remplacement de Canalisation d'Eaux Usées", metaTitle: "Remplacement Canalisation Eaux Usées Val d'Oise — EU/EP", metaDesc: "Remplacement de canalisation d'eaux usées (EU) ou eaux pluviales (EP) dans le Val d'Oise. PVC CR8/CR16, pente réglementaire. Devis gratuit.", intro: "Les canalisations d'eaux usées (EU) et d'eaux pluviales (EP) doivent respecter des pentes minimales et des diamètres réglementaires.", content: "Normes à respecter : pente minimum de 1 cm/m pour les EU, diamètre minimum 100 mm pour les EU et 100 mm pour les EP. En Val d'Oise, la séparation des réseaux EU/EP est obligatoire dans les zones d'assainissement séparatif. Nos artisans posent les canalisations en PVC CR8 (ou CR16 sous voirie) avec joints élastomères, sur lit de sable compacté, avec les regards de visite réglementaires tous les 30 mètres maximum et à chaque changement de direction." },
  { slug: "canalisation-terrain-argileux", category: "technique", h1: "Canalisation sur Terrain Argileux — Techniques Adaptées", metaTitle: "Canalisation Terrain Argileux Val d'Oise — Pose Spéciale Anti-Mouvement", metaDesc: "Pose de canalisation sur terrain argileux dans le Val d'Oise. Techniques anti-mouvement de sol : PEHD flexible, lit de sable renforcé.", intro: "Les terrains argileux du Val d'Oise (Franconville, Montmorency, Cormeilles) imposent des techniques de pose spécifiques pour prévenir les ruptures.", content: "L'argile gonfle en présence d'eau et se rétracte en sécheresse, créant des mouvements de sol qui déforment et cassent les canalisations rigides. Solutions adaptées : utilisation de PEHD (plus flexible que le PVC), pose sur lit de sable drainant de 20 cm minimum, remblai en matériau granulaire (pas d'argile), joints souples absorbant les mouvements différentiels. En cas de risque élevé, le chemisage continu (sans joints) est recommandé." },
  { slug: "mise-en-conformite-assainissement", category: "service", h1: "Mise en Conformité Assainissement — Val d'Oise", metaTitle: "Mise en Conformité Assainissement Val d'Oise — Diagnostic + Travaux", metaDesc: "Mise en conformité de votre réseau d'assainissement dans le Val d'Oise. Diagnostic, travaux de mise aux normes, attestation de conformité.", intro: "La mise en conformité de votre installation d'assainissement est exigée lors d'une vente immobilière ou d'un contrôle du SPANC.", content: "Le diagnostic d'assainissement est obligatoire lors de la vente d'un bien immobilier non raccordé au tout-à-l'égout (contrôle SPANC). Si le diagnostic révèle une non-conformité, l'acquéreur dispose d'un an pour réaliser les travaux de mise aux normes. Pour les installations raccordées au collectif, le contrôle de conformité vérifie : la séparation EU/EP, les pentes, les regards, et le bon raccordement au réseau public. Nos artisans réalisent le diagnostic et les travaux de mise en conformité." },
  { slug: "terrassement-canalisation", category: "technique", h1: "Terrassement pour Canalisation — Techniques et Coûts", metaTitle: "Terrassement Canalisation Val d'Oise — Tranchée, Blindage, Remblai", metaDesc: "Terrassement pour pose de canalisation dans le Val d'Oise. Tranchée mécanique ou manuelle, blindage, remblai compacté. À partir de 30€/ml.", intro: "Le terrassement représente une part importante du coût d'un remplacement de canalisation (30 à 40% du total).", content: "Étapes du terrassement professionnel : piquetage et marquage des réseaux existants (DICT obligatoire), ouverture de la tranchée à la mini-pelle ou manuellement selon l'accessibilité, mise en place du blindage de fouille pour les tranchées de plus de 1,30 m de profondeur (obligation de sécurité), préparation du fond de fouille (lit de sable 10 cm), pose de la canalisation, remblai en matériau sélectionné par couches de 20 cm avec compactage, et remise en état de surface (enrobé, béton, terre végétale)." },
  { slug: "canalisation-sous-dalle-beton", category: "technique", h1: "Canalisation Sous Dalle Béton — Remplacement Sans Tout Casser", metaTitle: "Canalisation Sous Dalle Béton Val d'Oise — Réparation Minimalement Invasive", metaDesc: "Canalisation sous dalle béton dans le Val d'Oise ? Chemisage sans tranchée ou remplacement ciblé. Pas besoin de tout casser.", intro: "Remplacer une canalisation qui passe sous une dalle béton (garage, terrasse, maison) peut sembler un cauchemar. Des solutions existent pour minimiser les dégâts.", content: "Deux approches : 1) Chemisage sans tranchée — une gaine est insérée depuis un regard et durcie en place, réparant la canalisation sans toucher à la dalle. 2) Remplacement ciblé — ouverture ponctuelle de la dalle uniquement aux points de raccordement, déviation du réseau en extérieur si possible. Dans les deux cas, un diagnostic caméra préalable est indispensable pour localiser exactement le problème et choisir la solution la moins invasive." },
  { slug: "canalisation-immeuble-copropriete", category: "service", h1: "Canalisation d'Immeuble en Copropriété — Diagnostic et Remplacement", metaTitle: "Canalisation Immeuble Copropriété Val d'Oise — Colonnes + Raccordements", metaDesc: "Problème de canalisation dans votre immeuble en copropriété ? Diagnostic colonnes de chute, remplacement parties communes. Val d'Oise.", intro: "Les immeubles collectifs du Val d'Oise (années 60-70) présentent souvent des colonnes de chute en fonte corrodée nécessitant un remplacement.", content: "Les colonnes de chute (évacuation verticale des eaux usées) des immeubles collectifs sont généralement en fonte. Après 50 ans, la corrosion interne et les fissures provoquent des fuites et des nuisances sonores. Le remplacement se fait étage par étage, en coordination avec le syndic de copropriété. Notre offre pour les copropriétés : diagnostic caméra de l'ensemble des colonnes, devis détaillé présenté en AG, travaux coordonnés pour minimiser la gêne des occupants, garantie décennale." },
  { slug: "entretien-preventif-canalisation", category: "service", h1: "Entretien Préventif des Canalisations — Éviter les Urgences", metaTitle: "Entretien Préventif Canalisation Val d'Oise — Curage Annuel", metaDesc: "Entretien préventif de vos canalisations dans le Val d'Oise. Curage annuel, inspection caméra, traitement anti-racines. Évitez les urgences.", intro: "Un entretien régulier de vos canalisations permet d'éviter les bouchons, les fuites et les remplacements coûteux.", content: "Programme d'entretien recommandé : Annuel — curage par hydrocurage pour éliminer les dépôts (calcaire, graisses, racines naissantes). Tous les 3 ans — inspection caméra pour détecter les fissures, affaissements ou intrusions de racines à un stade précoce. Tous les 5 ans — traitement anti-racines si arbres à proximité. Nos contrats d'entretien annuel offrent une tranquillité d'esprit et des tarifs préférentiels. Un curage préventif coûte 10 fois moins cher qu'un remplacement d'urgence." },

  // ═══ SITUATIONS SPÉCIFIQUES ═══
  { slug: "canalisation-avant-achat-immobilier", category: "service", h1: "Vérification Canalisation Avant Achat Immobilier", metaTitle: "Vérification Canalisation Avant Achat Immobilier Val d'Oise", metaDesc: "Vous achetez une maison dans le Val d'Oise ? Faites inspecter les canalisations avant de signer. Diagnostic caméra + rapport détaillé.", intro: "L'état des canalisations est rarement vérifié lors d'un achat immobilier. Pourtant, un remplacement peut coûter plusieurs milliers d'euros.", content: "Un diagnostic caméra préventif avant l'achat vous permet de connaître l'état exact du réseau d'évacuation : fissures, racines, affaissements, contre-pentes, matériaux obsolètes (plomb, amiante-ciment). Ce diagnostic peut servir d'argument de négociation si des travaux sont nécessaires. Dans le Val d'Oise, les maisons d'avant 1970 ont souvent des canalisations en fonte ou grès en fin de vie. Coût du diagnostic : 200 à 400€ — un investissement dérisoire face au coût potentiel d'un remplacement." },
  { slug: "canalisation-apres-travaux-vrd", category: "technique", h1: "Canalisation Endommagée Après Travaux VRD — Que Faire ?", metaTitle: "Canalisation Endommagée Travaux VRD Val d'Oise — Responsabilité et Réparation", metaDesc: "Canalisation cassée suite à des travaux de voirie ou terrassement ? Constat, responsabilité de l'entreprise, réparation urgente. Val d'Oise.", intro: "Les travaux de voirie, terrassement ou construction endommagent parfois les canalisations existantes. La responsabilité de l'entreprise est engagée.", content: "Si vos canalisations ont été endommagées par des travaux tiers : 1) Prenez des photos immédiatement, 2) Notez le nom de l'entreprise et le numéro de chantier, 3) Faites constater les dégâts par un professionnel indépendant (nous), 4) Contactez l'entreprise pour signaler le sinistre. Notre rapport d'expertise servira de preuve pour votre demande d'indemnisation. En cas d'urgence (fuite active), nous sécurisons et réparons immédiatement." },
  { slug: "normes-nf-canalisation-assainissement", category: "technique", h1: "Normes NF pour Canalisations d'Assainissement — Guide", metaTitle: "Normes NF Canalisation Assainissement — NF EN 1401, DTU 64.1", metaDesc: "Quelles normes pour vos canalisations d'assainissement ? NF EN 1401 (PVC), NF EN 12201 (PEHD), DTU 64.1, DTU 60.33. Guide complet.", intro: "Les canalisations d'assainissement doivent respecter des normes strictes pour garantir leur durabilité et la conformité de l'installation.", content: "Normes principales : NF EN 1401-1 — tubes PVC pour assainissement (classes de rigidité CR4, CR8, CR16). NF EN 12201 — tubes PEHD pour alimentation en eau et assainissement sous pression. DTU 64.1 — mise en œuvre des dispositifs d'assainissement non collectif. DTU 60.33 — canalisations en PVC non plastifié. NF EN 476 — exigences générales pour les composants des réseaux de branchement. Nos artisans du Val d'Oise respectent l'ensemble de ces normes et fournissent les certificats de conformité des matériaux utilisés." },
  // ═══ LOT 2 — VILLES COMPLÉMENTAIRES ═══
  { slug: "remplacement-canalisation-sarcelles", category: "ville", h1: "Remplacement de Canalisation à Sarcelles (95200)", metaTitle: "Remplacement Canalisation Sarcelles (95200) — Grands Ensembles", metaDesc: "Remplacement de canalisation à Sarcelles (95200). Grands ensembles années 60, réseaux collectifs en fonte. Artisans locaux, devis gratuit.", intro: "Sarcelles possède l'un des plus grands parcs de logements collectifs du Val d'Oise, avec des réseaux de canalisations datant des années 60.", content: "Les grands ensembles de Sarcelles (Lochères, Chardonnerettes, Rosiers) ont des colonnes de chute et réseaux collectifs en fonte qui arrivent en fin de vie après 60 ans. Le remplacement de ces canalisations de gros diamètre (200 à 300 mm) nécessite une coordination avec le syndic de copropriété et les occupants. Nos artisans ont une expérience significative en milieu collectif : intervention par palier pour minimiser la gêne, travail propre dans les parties communes, remise en service rapide." },
  { slug: "reparation-fuite-garges-les-gonesse", category: "ville", h1: "Réparation de Fuite à Garges-lès-Gonesse (95140)", metaTitle: "Réparation Fuite Garges-lès-Gonesse (95140) — Détection Rapide", metaDesc: "Fuite de canalisation à Garges-lès-Gonesse (95140) ? Détection acoustique et réparation ciblée. Quartiers résidentiels, intervention sous 1h.", intro: "Garges-lès-Gonesse, avec ses quartiers résidentiels et ses ensembles des années 60-70, présente des canalisations vieillissantes sujettes aux fuites.", content: "Les quartiers de la Dame Blanche, des Doucettes et de la Muette ont des réseaux en fonte et PVC première génération qui se fragilisent. La détection de fuite par écoute acoustique est la méthode la plus adaptée en zone urbaine dense. Nos techniciens localisent la fuite sans casser, puis effectuent une réparation ciblée. Intervention rapide depuis notre base du Val d'Oise." },
  { slug: "diagnostic-camera-montmorency", category: "ville", h1: "Diagnostic Caméra Canalisation à Montmorency (95160)", metaTitle: "Diagnostic Caméra Canalisation Montmorency (95160) — Coteau Argileux", metaDesc: "Inspection caméra de canalisation à Montmorency (95160). Coteau boisé, terrain argileux, canalisations soumises aux mouvements de sol.", intro: "Montmorency, sur son coteau boisé, est particulièrement exposée aux mouvements de terrain argileux qui déforment les canalisations.", content: "Le coteau de Montmorency est classé en zone d'aléa moyen à fort pour le retrait-gonflement des argiles. Les canalisations subissent des contraintes mécaniques qui provoquent fissures et affaissements. L'inspection caméra permet de détecter ces déformations avant qu'elles ne causent des ruptures. Notre caméra HD avec mesure de pente identifie les zones critiques et permet de planifier les interventions préventives." },
  { slug: "canalisation-urgence-villiers-le-bel", category: "ville", h1: "Canalisation en Urgence à Villiers-le-Bel (95400)", metaTitle: "Canalisation Urgence Villiers-le-Bel (95400) — Intervention 7j/7", metaDesc: "Urgence canalisation à Villiers-le-Bel (95400) ? Fuite, bouchon, refoulement. Artisans du Val d'Oise sous 1h. Devis gratuit.", intro: "Villiers-le-Bel, avec son habitat mixte collectif et pavillonnaire, nécessite des artisans canalisateurs polyvalents et réactifs.", content: "Nos artisans interviennent dans tous les quartiers de Villiers-le-Bel : centre ancien, ZAC Derrière les Murs de Monseigneur, quartier de la Cerisaie. Réseaux des années 60-70 en fonte et PVC, nécessitant souvent des remplacements complets. Intervention sous 1 heure, 7j/7, devis gratuit sur place." },
  { slug: "remplacement-canalisation-eaubonne", category: "ville", h1: "Remplacement de Canalisation à Eaubonne (95600)", metaTitle: "Remplacement Canalisation Eaubonne (95600) — Vallée de Montmorency", metaDesc: "Remplacement de canalisation à Eaubonne (95600). Quartiers pavillonnaires vallée de Montmorency, terrain argileux. Garantie décennale.", intro: "Eaubonne, dans la vallée de Montmorency, possède un parc pavillonnaire dont les canalisations individuelles nécessitent un entretien et un remplacement réguliers.", content: "Le terrain argileux de la vallée de Montmorency provoque des mouvements de sol saisonniers qui fissurent les canalisations rigides (fonte, PVC ancien). Nos artisans utilisent du PEHD flexible pour les remplacements, posé sur lit de sable drainant pour absorber les mouvements différentiels. Chaque chantier inclut la remise en état complète du jardin." },
  { slug: "reparation-fuite-saint-gratien", category: "ville", h1: "Réparation de Fuite à Saint-Gratien (95210)", metaTitle: "Réparation Fuite Saint-Gratien (95210) — Lac d'Enghien", metaDesc: "Fuite de canalisation à Saint-Gratien (95210) ? Proximité lac d'Enghien, terrains humides. Détection et réparation rapide.", intro: "Saint-Gratien, proche du lac d'Enghien, est soumise à des nappes phréatiques hautes qui fragilisent les canalisations enterrées.", content: "L'humidité permanente du sous-sol à Saint-Gratien accélère la corrosion des canalisations métalliques et peut provoquer des infiltrations. La détection de fuite dans ces conditions nécessite une expertise spécifique : nos techniciens distinguent l'eau de la fuite de l'eau de nappe grâce à des techniques de traçage. Réparation avec matériaux résistants à l'humidité permanente." },
  { slug: "diagnostic-camera-cormeilles-en-parisis", category: "ville", h1: "Diagnostic Caméra à Cormeilles-en-Parisis (95240)", metaTitle: "Diagnostic Caméra Cormeilles-en-Parisis (95240) — Terrain Gypse", metaDesc: "Inspection caméra canalisation à Cormeilles-en-Parisis (95240). Anciennes carrières de gypse, terrain instable. Rapport vidéo détaillé.", intro: "Cormeilles-en-Parisis, avec ses anciennes carrières de gypse, présente un sous-sol instable qui peut endommager les canalisations.", content: "Le gypse se dissout au contact de l'eau, créant des cavités souterraines (fontis) qui provoquent des affaissements de terrain. Les canalisations situées dans ces zones sont particulièrement vulnérables. L'inspection caméra avec localisation GPS permet de cartographier l'état du réseau et de prioriser les interventions avant que les dégâts ne s'aggravent." },
  { slug: "canalisation-urgence-herblay", category: "ville", h1: "Canalisation en Urgence à Herblay-sur-Seine (95220)", metaTitle: "Canalisation Urgence Herblay-sur-Seine (95220) — Bord de Seine", metaDesc: "Urgence canalisation à Herblay-sur-Seine (95220) ? Bord de Seine, terrains alluviaux. Intervention sous 1h, artisans locaux.", intro: "Herblay-sur-Seine, en bord de Seine, est soumise aux contraintes des terrains alluviaux et des nappes phréatiques élevées.", content: "Les terrains alluviaux d'Herblay sont composés de sables et graviers gorgés d'eau qui compliquent les travaux de terrassement. Nos artisans maîtrisent les techniques de pose en terrain humide : pompage, blindage étanche, et utilisation de PEHD résistant à l'immersion permanente. Intervention sous 1 heure dans tout Herblay et les communes limitrophes." },
  { slug: "remplacement-canalisation-osny", category: "ville", h1: "Remplacement de Canalisation à Osny (95520)", metaTitle: "Remplacement Canalisation Osny (95520) — Agglomération Cergy-Pontoise", metaDesc: "Remplacement canalisation à Osny (95520). Quartiers 70-80 à rénover. Artisan canalisateur local, garantie décennale, devis gratuit.", intro: "Osny, dans l'agglomération de Cergy-Pontoise, possède des quartiers résidentiels des années 70-80 dont les canalisations arrivent en fin de vie.", content: "Les lotissements d'Osny construits entre 1970 et 1985 ont des canalisations PVC première génération qui se fragilisent après 40-50 ans. Les signes de vieillissement : bouchons récurrents, fuites aux joints, contre-pentes. Le remplacement par du PVC CR8 nouvelle génération ou du PEHD assure 50 ans de tranquillité. Nos artisans connaissent les spécificités des réseaux de l'agglomération cergyssoise." },
  { slug: "reparation-fuite-soisy-sous-montmorency", category: "ville", h1: "Réparation de Fuite à Soisy-sous-Montmorency (95230)", metaTitle: "Réparation Fuite Soisy-sous-Montmorency (95230)", metaDesc: "Fuite canalisation à Soisy-sous-Montmorency (95230). Vallée de Montmorency, canalisations 60-80. Détection et réparation rapide.", intro: "Soisy-sous-Montmorency, dans la vallée de Montmorency, possède des canalisations pavillonnaires des années 60-80 sujettes aux fuites.", content: "Les quartiers résidentiels de Soisy ont des réseaux individuels en PVC ou fonte qui vieillissent. Les mouvements du terrain argileux de la vallée de Montmorency accentuent les contraintes sur les joints et raccords. Nos techniciens localisent les fuites par écoute acoustique et effectuent des réparations ciblées. Devis gratuit, intervention rapide." },

  // ═══ LOT 2 — LONG-TAILS SUPPLÉMENTAIRES ═══
  { slug: "canalisation-bouchee-calcaire", category: "probleme", h1: "Canalisation Bouchée par le Calcaire — Traitement", metaTitle: "Canalisation Bouchée Calcaire Val d'Oise — Détartrage Professionnel", metaDesc: "Canalisation bouchée par le calcaire dans le Val d'Oise ? Eau très calcaire en Île-de-France. Détartrage par hydrocurage et traitement préventif.", intro: "L'eau du Val d'Oise est très calcaire (dureté 25 à 35°f), ce qui provoque l'entartrage progressif des canalisations.", content: "Le calcaire se dépose sur les parois internes des canalisations, réduisant progressivement le diamètre utile jusqu'au bouchon complet. L'hydrocurage haute pression élimine les dépôts calcaires sans endommager les tuyaux. En prévention, un curage annuel est recommandé dans les zones à eau dure du Val d'Oise. Pour les canalisations d'eau potable, l'installation d'un adoucisseur d'eau peut réduire considérablement l'entartrage." },
  { slug: "canalisation-bouchee-graisse", category: "probleme", h1: "Canalisation Bouchée par la Graisse — Restaurant et Particulier", metaTitle: "Canalisation Bouchée Graisse Val d'Oise — Débouchage + Bac à Graisse", metaDesc: "Canalisation bouchée par les graisses ? Débouchage professionnel et installation de bac à graisse. Restaurants et particuliers Val d'Oise.", intro: "Les graisses alimentaires sont la cause n°1 de bouchon dans les canalisations de cuisine, chez les particuliers comme chez les restaurateurs.", content: "Les graisses se solidifient en refroidissant dans les canalisations, formant un bouchon compact qui se renforce avec le temps. Le débouchage par hydrocurage à eau chaude (80°C) sous pression est la méthode la plus efficace. Pour les professionnels de la restauration, l'installation d'un bac à graisse est obligatoire (règlement sanitaire). Pour les particuliers, un entretien préventif mensuel (eau bouillante + bicarbonate) limite l'accumulation." },
  { slug: "canalisation-wc-bouche", category: "probleme", h1: "Canalisation WC Bouchée — Débouchage Professionnel", metaTitle: "WC Bouché Val d'Oise — Débouchage Canalisation Toilettes Urgent", metaDesc: "WC bouché dans le Val d'Oise ? Débouchage professionnel par furet ou hydrocurage. Intervention rapide, pas de dégâts. Devis gratuit.", intro: "Des toilettes bouchées constituent une urgence quotidienne qui nécessite une intervention rapide pour rétablir le confort sanitaire.", content: "Les causes de WC bouchés : accumulation de papier, lingettes (même dites 'biodégradables'), objets tombés accidentellement, ou problème en aval sur la canalisation d'évacuation. Le débouchage professionnel par furet rotatif ou hydrocurage résout le problème sans endommager la céramique ni les joints. Si les bouchons sont récurrents, une inspection caméra est recommandée pour vérifier l'état de la canalisation en aval." },
  { slug: "fuite-eau-apres-compteur", category: "probleme", h1: "Fuite d'Eau Après Compteur — Responsabilité et Réparation", metaTitle: "Fuite Eau Après Compteur Val d'Oise — Qui Paye ? Loi Warsmann", metaDesc: "Fuite d'eau après le compteur dans le Val d'Oise ? Responsabilité du propriétaire. Détection, réparation et plafonnement facture (loi Warsmann).", intro: "Une fuite après le compteur est à la charge du propriétaire, mais la loi Warsmann permet de plafonner la facture d'eau en cas de fuite cachée.", content: "La loi Warsmann (article L2224-12-4 du CGCT) prévoit que votre facture d'eau soit plafonnée au double de votre consommation habituelle en cas de fuite sur canalisation enterrée après compteur. Conditions : la fuite doit être réparée par un professionnel, et l'attestation de réparation doit être transmise au service des eaux dans le mois suivant la réparation. Nos artisans fournissent systématiquement cette attestation." },
  { slug: "remplacement-regard-canalisation", category: "service", h1: "Remplacement de Regard de Canalisation", metaTitle: "Remplacement Regard Canalisation Val d'Oise — Béton ou PVC", metaDesc: "Remplacement de regard de canalisation dans le Val d'Oise. Regard béton ou PVC, tampon fonte. Mise en conformité, devis gratuit.", intro: "Les regards de visite permettent l'accès au réseau pour l'entretien et le curage. Un regard fissuré ou effondré compromet l'étanchéité du réseau.", content: "Les regards en béton anciens se fissurent avec le temps, permettant l'infiltration des eaux de pluie et des racines dans le réseau d'eaux usées. Le remplacement par un regard PVC préfabriqué offre une meilleure étanchéité et une durée de vie supérieure. Nos artisans réalisent : dépose de l'ancien regard, terrassement, pose du nouveau regard sur radier béton, raccordement aux canalisations entrantes et sortantes, pose du tampon fonte ou PVC." },
  { slug: "pompe-de-relevage-eaux-usees", category: "service", h1: "Installation Pompe de Relevage Eaux Usées", metaTitle: "Pompe de Relevage Eaux Usées Val d'Oise — Installation et Remplacement", metaDesc: "Installation ou remplacement de pompe de relevage dans le Val d'Oise. Sous-sol, cave, terrain en contrebas. Artisan spécialisé.", intro: "Une pompe de relevage est nécessaire quand les eaux usées doivent remonter vers le réseau public situé plus haut que l'habitation.", content: "Cas nécessitant une pompe de relevage : sous-sol aménagé avec sanitaires en dessous du niveau du tout-à-l'égout, terrain en contrebas de la voirie, longue distance jusqu'au point de raccordement. Nos artisans installent des pompes de relevage eaux usées (avec broyeur si nécessaire) conformes à la norme NF EN 12050. L'installation comprend : poste de relevage, canalisation de refoulement en PEHD, clapet anti-retour, et raccordement électrique." },
  { slug: "separation-eaux-usees-eaux-pluviales", category: "technique", h1: "Séparation Eaux Usées / Eaux Pluviales — Mise en Conformité", metaTitle: "Séparation EU/EP Val d'Oise — Obligation et Travaux", metaDesc: "Séparation des eaux usées et eaux pluviales obligatoire dans le Val d'Oise. Diagnostic, travaux de mise en conformité. Devis gratuit.", intro: "Dans les zones d'assainissement séparatif du Val d'Oise, les eaux usées (EU) et les eaux pluviales (EP) doivent emprunter deux réseaux distincts.", content: "De nombreuses maisons anciennes du Val d'Oise évacuent encore les eaux de pluie et les eaux usées dans la même canalisation (réseau unitaire). Lors du passage en assainissement séparatif, la commune impose la mise en conformité : création d'un réseau séparé pour les eaux pluviales. Nos artisans réalisent le diagnostic de l'installation existante, la création du réseau EP séparé, et le raccordement aux deux collecteurs publics distincts." },
  { slug: "canalisation-amiante-ciment", category: "materiau", h1: "Canalisation en Amiante-Ciment — Remplacement Sécurisé", metaTitle: "Canalisation Amiante-Ciment Val d'Oise — Dépose et Remplacement", metaDesc: "Canalisations en amiante-ciment dans le Val d'Oise ? Dépose sécurisée par artisan certifié SS4, remplacement aux normes. Devis gratuit.", intro: "Les canalisations en amiante-ciment (fibrociment), posées entre 1950 et 1997, contiennent de l'amiante et nécessitent une dépose sécurisée.", content: "L'amiante-ciment était très utilisé pour les canalisations d'eau potable et d'assainissement. Sa manipulation lors du remplacement nécessite des précautions strictes : personnel formé sous-section 4 (SS4), humidification des tuyaux avant découpe, aspiration des poussières, conditionnement en sacs étanches et évacuation vers un centre de traitement agréé. Nos artisans certifiés SS4 réalisent le remplacement en toute sécurité par du PVC ou PEHD." },
  { slug: "cuvelage-sous-sol-etanche", category: "technique", h1: "Cuvelage de Sous-Sol — Étanchéité Contre les Infiltrations", metaTitle: "Cuvelage Sous-Sol Val d'Oise — Étanchéité Intérieure et Extérieure", metaDesc: "Infiltrations dans votre sous-sol dans le Val d'Oise ? Cuvelage étanche, drainage, pompe de relevage. Solution durable.", intro: "Le cuvelage est la solution définitive contre les infiltrations d'eau dans un sous-sol ou une cave, particulièrement en zone de nappe haute.", content: "Deux techniques de cuvelage : 1) Cuvelage intérieur — application d'un enduit étanche (mortier de cuvelage) sur les murs et le sol du sous-sol. Solution moins coûteuse mais ne traite pas la cause. 2) Cuvelage extérieur — application d'une membrane d'étanchéité sur la face extérieure des murs enterrés, combinée à un drainage périphérique. Solution plus durable mais nécessite un terrassement complet autour de la maison. En Val d'Oise, les zones de Bezons, Herblay et Saint-Ouen-l'Aumône sont particulièrement concernées." },
  { slug: "devis-canalisation-en-ligne", category: "prix", h1: "Devis Canalisation en Ligne — Gratuit et Sans Engagement", metaTitle: "Devis Canalisation Val d'Oise — Gratuit en Ligne ou Sur Place", metaDesc: "Demandez votre devis canalisation gratuit dans le Val d'Oise. En ligne ou sur place. Réponse sous 30 minutes. Sans engagement.", intro: "Obtenir un devis précis pour des travaux de canalisation nécessite un diagnostic sur place. Mais vous pouvez initier la demande en ligne.", content: "Notre processus de devis : 1) Remplissez le formulaire en ligne (type de problème, adresse, photos si possible) ou appelez-nous directement. 2) Un artisan vous rappelle sous 30 minutes pour affiner le diagnostic. 3) Visite sur place gratuite avec inspection caméra si nécessaire. 4) Remise d'un devis détaillé poste par poste (terrassement, fourniture, main d'œuvre, remise en état). Aucun engagement, aucun frais de déplacement." },
  { slug: "garantie-decennale-canalisation", category: "service", h1: "Garantie Décennale sur Travaux de Canalisation — Explications", metaTitle: "Garantie Décennale Canalisation — Durée, Couverture, Attestation", metaDesc: "Garantie décennale sur les travaux de canalisation : que couvre-t-elle ? Durée 10 ans, dommages structurels, attestation d'assurance.", intro: "La garantie décennale est obligatoire pour tous les travaux de canalisation affectant la solidité ou l'habitabilité d'un bâtiment.", content: "La garantie décennale (loi Spinetta du 4 janvier 1978) couvre pendant 10 ans les dommages qui compromettent la solidité de l'ouvrage ou le rendent impropre à sa destination. Pour les travaux de canalisation, cela inclut : les fuites structurelles, les affaissements de canalisation enterrée, les défauts d'étanchéité du réseau d'assainissement, et les infiltrations causées par un défaut de pose. Tous nos artisans sont couverts par une assurance décennale dont l'attestation vous est fournie avec la facture." },
  { slug: "canalisation-maison-ancienne", category: "probleme", h1: "Canalisation de Maison Ancienne — Diagnostic et Rénovation", metaTitle: "Canalisation Maison Ancienne Val d'Oise — Diagnostic et Remplacement", metaDesc: "Maison ancienne dans le Val d'Oise ? Canalisations en fonte, plomb ou grès à remplacer. Diagnostic caméra + devis de rénovation gratuit.", intro: "Les maisons anciennes du Val d'Oise (avant 1970) possèdent souvent des canalisations en fonte, plomb ou grès qui nécessitent une rénovation complète.", content: "Signes de canalisations vieillissantes : bouchons fréquents, odeurs d'égout, fuites récurrentes, eau rougeâtre (corrosion fonte), traces d'humidité en sous-sol. Un diagnostic caméra révèle l'état réel du réseau et permet de planifier la rénovation. Nos artisans proposent un remplacement progressif (par priorité) ou complet, avec mise en conformité aux normes actuelles (séparation EU/EP, pentes réglementaires, raccordement au collectif)." },
  { slug: "canalisation-lotissement-neuf", category: "service", h1: "Canalisation pour Lotissement Neuf — Pose et Raccordement", metaTitle: "Canalisation Lotissement Neuf Val d'Oise — VRD et Raccordement", metaDesc: "Pose de canalisations pour lotissement neuf dans le Val d'Oise. Réseaux EU/EP, branchements, regards. Conforme aux DTU.", intro: "La création d'un lotissement nécessite la pose de réseaux de canalisations complets : eaux usées, eaux pluviales et eau potable.", content: "Nos artisans réalisent l'ensemble des travaux de VRD (Voirie et Réseaux Divers) pour les lotissements neufs : tranchées, pose des réseaux EU et EP séparés en PVC CR8/CR16, branchements individuels, regards de visite et d'inspection, raccordement au réseau public. Tous les travaux sont réalisés conformément aux DTU en vigueur et au cahier des charges du lotisseur. Essais d'étanchéité par tronçon avant remblaiement." },
  { slug: "renovation-salle-de-bain-canalisation", category: "service", h1: "Rénovation Salle de Bain — Canalisations et Évacuations", metaTitle: "Rénovation Salle Bain Canalisation Val d'Oise — Évacuation + Alimentation", metaDesc: "Rénovation de salle de bain dans le Val d'Oise ? Modification des canalisations d'évacuation et d'alimentation. Artisan qualifié.", intro: "La rénovation d'une salle de bain implique souvent la modification ou le remplacement des canalisations d'alimentation et d'évacuation.", content: "Travaux courants : déplacement de la douche ou de la baignoire (modification des évacuations), remplacement des canalisations en plomb par du cuivre ou PER, création d'une évacuation pour douche à l'italienne (receveur extra-plat nécessitant une pente précise), remplacement du siphon de sol. Nos artisans maîtrisent les contraintes de pente et de diamètre pour garantir un écoulement parfait." },
  { slug: "canalisation-terrain-en-pente", category: "technique", h1: "Canalisation sur Terrain en Pente — Pose Adaptée", metaTitle: "Canalisation Terrain en Pente Val d'Oise — Techniques de Pose", metaDesc: "Pose de canalisation sur terrain en pente dans le Val d'Oise (Montmorency, Sannois, Cormeilles). Techniques anti-glissement.", intro: "Les terrains en pente du Val d'Oise (coteaux de Montmorency, Sannois, Cormeilles) nécessitent des techniques de pose spécifiques.", content: "Sur terrain pentu, les canalisations sont soumises à des forces de glissement qui peuvent provoquer des déboîtements de joints. Solutions : ancrage de la canalisation par butées en béton aux changements de direction, utilisation de raccords à joint verrouillé anti-déboîtement, pose en tranchée avec paliers horizontaux (escalier), et drainage latéral pour éviter l'érosion du lit de pose par les eaux de ruissellement." },
  { slug: "test-etancheite-canalisation", category: "technique", h1: "Test d'Étanchéité de Canalisation — Norme et Procédure", metaTitle: "Test Étanchéité Canalisation Val d'Oise — Norme NF EN 1610", metaDesc: "Test d'étanchéité de canalisation dans le Val d'Oise. Obligatoire après pose neuve. Conforme NF EN 1610. Attestation fournie.", intro: "Le test d'étanchéité est obligatoire après toute pose de canalisation neuve ou réparation importante, conformément à la norme NF EN 1610.", content: "Deux méthodes normalisées : 1) Test à l'eau — remplissage du tronçon et mesure de la perte de volume sur 30 minutes. La perte admissible est de 0,15 l/m²/mn. 2) Test à l'air — mise sous pression d'air à 10 kPa et mesure de la chute de pression. Plus rapide que le test à l'eau. Nos artisans réalisent systématiquement ce test après chaque intervention de remplacement et fournissent un procès-verbal de test attestant la conformité." },
  { slug: "canalisation-pehd-soudure", category: "materiau", h1: "Canalisation PEHD — Soudure et Pose Professionnelle", metaTitle: "Canalisation PEHD Val d'Oise — Soudure Bout à Bout et Électrofusion", metaDesc: "Pose de canalisation PEHD dans le Val d'Oise. Soudure bout à bout ou électrofusion. Matériau le plus durable, 50+ ans.", intro: "Le PEHD (polyéthylène haute densité) est le matériau le plus performant pour les canalisations, avec une durée de vie supérieure à 50 ans.", content: "Le PEHD PE100 offre une résistance exceptionnelle : pas de corrosion, flexibilité (absorbe les mouvements de terrain), résistance aux racines et aux produits chimiques. Deux techniques de raccordement : soudure bout à bout (miroir chauffant) pour les gros diamètres, et électrofusion (raccord avec résistance intégrée) pour les petits diamètres et les piquages. Nos artisans sont certifiés pour la soudure PEHD selon la norme NF EN 12201." },
  { slug: "fosse-septique-vers-tout-a-legout", category: "service", h1: "Suppression Fosse Septique et Raccordement Tout-à-l'Égout", metaTitle: "Suppression Fosse Septique Val d'Oise — Raccordement Tout-à-l'Égout", metaDesc: "Suppression de fosse septique et raccordement au tout-à-l'égout dans le Val d'Oise. Obligation légale, démarches et travaux.", intro: "Quand le réseau d'assainissement collectif arrive dans votre rue, la suppression de votre fosse septique et le raccordement sont obligatoires.", content: "Les étapes : 1) Vérification auprès de la mairie que votre rue est bien desservie par le réseau collectif. 2) Demande d'autorisation de raccordement. 3) Vidange et neutralisation de la fosse septique (remplissage en sable ou démolition). 4) Pose de la canalisation de raccordement entre la maison et le regard public. 5) Essai d'étanchéité et réception par le service d'assainissement. Nos artisans gèrent l'ensemble du processus, y compris les démarches administratives." },
  { slug: "colonne-evacuations-immeuble", category: "service", h1: "Remplacement Colonne d'Évacuation d'Immeuble", metaTitle: "Remplacement Colonne Évacuation Immeuble Val d'Oise — Copropriété", metaDesc: "Remplacement de colonne d'évacuation (chute EU/EP) en immeuble dans le Val d'Oise. Coordination syndic, travaux par palier.", intro: "Le remplacement d'une colonne d'évacuation d'immeuble est un chantier complexe qui nécessite une coordination minutieuse avec le syndic et les occupants.", content: "Les colonnes de chute en fonte des immeubles des années 50-70 du Val d'Oise arrivent en fin de vie. Le remplacement se fait étage par étage, généralement du haut vers le bas, avec coupure de l'eau limitée à quelques heures par palier. Nous utilisons du PVC acoustique (insonorisant) pour remplacer la fonte, réduisant significativement les nuisances sonores. Planning type : 1 à 2 jours par colonne pour un immeuble R+4." },
  { slug: "canalisation-gaz-traceur-detection", category: "technique", h1: "Détection de Fuite par Gaz Traceur — Technique de Précision", metaTitle: "Détection Fuite Gaz Traceur Val d'Oise — Hydrogène-Azote Précision", metaDesc: "Détection de fuite par injection de gaz traceur (H2/N2) dans le Val d'Oise. La technique la plus précise pour les fuites invisibles.", intro: "Le gaz traceur est la technique ultime de détection de fuite, utilisée quand l'écoute acoustique et la corrélation ne suffisent pas.", content: "Un mélange hydrogène (5%) et azote (95%) est injecté dans la canalisation sous pression. L'hydrogène, molécule la plus petite et la plus légère, s'échappe par la moindre fissure et traverse le sol pour remonter en surface. Un détecteur ultra-sensible balaye le sol au-dessus de la canalisation et repère la concentration maximale d'hydrogène, indiquant la position exacte de la fuite. Précision : ±5 cm. Cette technique fonctionne même sous béton, carrelage ou enrobé." },
  { slug: "canalisation-industrielle-val-doise", category: "service", h1: "Canalisation Industrielle — Entreprises du Val d'Oise", metaTitle: "Canalisation Industrielle Val d'Oise — Entreprises et Zones d'Activités", metaDesc: "Travaux de canalisation pour entreprises et zones d'activités du Val d'Oise. Réseaux EU/EP industriels, regards, séparateurs.", intro: "Les entreprises et zones d'activités du Val d'Oise (ZAC de Gonesse, zone aéroportuaire de Roissy) ont des besoins spécifiques en canalisation.", content: "Les canalisations industrielles présentent des contraintes spécifiques : gros diamètres (300 à 600 mm), effluents agressifs nécessitant des matériaux résistants (PEHD, inox), obligation de prétraitement (séparateur à hydrocarbures, bac à graisse industriel), débits importants. Nos artisans interviennent pour les entreprises du Val d'Oise : réseaux EU/EP, branchements industriels, séparateurs à hydrocarbures, postes de relevage haute capacité." },
  { slug: "debouchage-colonne-immeuble", category: "probleme", h1: "Débouchage de Colonne d'Immeuble — Intervention Copropriété", metaTitle: "Débouchage Colonne Immeuble Val d'Oise — Hydrocurage Copropriété", metaDesc: "Colonne d'immeuble bouchée dans le Val d'Oise ? Débouchage par hydrocurage professionnel. Coordination syndic, intervention rapide.", intro: "Une colonne d'évacuation bouchée dans un immeuble affecte tous les étages en amont et constitue une urgence de copropriété.", content: "Le débouchage d'une colonne d'immeuble se fait généralement depuis le pied de colonne (sous-sol ou rez-de-chaussée) ou depuis le toit. L'hydrocurage haute pression (200 à 350 bars) est la méthode la plus efficace pour les colonnes de gros diamètre (100 à 150 mm). En complément, une inspection caméra vérifie l'état de la colonne et détecte d'éventuelles fissures ou déformations nécessitant un remplacement." },
  { slug: "assainissement-non-collectif-spanc", category: "service", h1: "Assainissement Non Collectif — Contrôle SPANC Val d'Oise", metaTitle: "Assainissement Non Collectif SPANC Val d'Oise — Diagnostic + Mise aux Normes", metaDesc: "Contrôle SPANC et mise aux normes de votre assainissement non collectif dans le Val d'Oise. Fosse, filtre, épandage. Devis gratuit.", intro: "Les habitations non raccordées au tout-à-l'égout doivent disposer d'un système d'assainissement individuel conforme, contrôlé par le SPANC.", content: "Le SPANC (Service Public d'Assainissement Non Collectif) contrôle les installations individuelles tous les 4 à 10 ans selon les communes du Val d'Oise. En cas de non-conformité, les travaux de mise aux normes sont à réaliser dans un délai d'un an (ou 2 ans en cas de vente). Nos artisans réalisent : diagnostic de l'installation existante, remplacement ou mise en conformité de la fosse toutes eaux, du filtre à sable ou du système d'épandage, et obtention de l'attestation de conformité SPANC." },
  { slug: "canalisation-apres-inondation", category: "urgence", h1: "Vérification Canalisation Après Inondation", metaTitle: "Canalisation Après Inondation Val d'Oise — Diagnostic et Nettoyage", metaDesc: "Inondation dans le Val d'Oise ? Vérification et nettoyage de vos canalisations post-inondation. Diagnostic caméra + curage sanitaire.", intro: "Après une inondation, les canalisations peuvent être endommagées, obstruées par des débris ou contaminées par des eaux polluées.", content: "Les inondations (fréquentes en bord de Seine et d'Oise dans le Val d'Oise) peuvent provoquer : introduction de boue et débris dans les canalisations, déplacement ou rupture des tuyaux par la pression de l'eau, contamination bactérienne du réseau. Notre intervention post-inondation : inspection caméra pour évaluer les dégâts, curage haute pression pour nettoyer les canalisations, réparation ou remplacement des tronçons endommagés, et désinfection si nécessaire." },
  { slug: "canalisation-piscine-evacuation", category: "service", h1: "Canalisation pour Piscine — Alimentation et Évacuation", metaTitle: "Canalisation Piscine Val d'Oise — Alimentation, Évacuation, Trop-Plein", metaDesc: "Installation canalisation pour piscine dans le Val d'Oise. Alimentation eau, évacuation vidange, trop-plein. Artisan qualifié.", intro: "L'installation d'une piscine nécessite des canalisations spécifiques pour l'alimentation en eau, l'évacuation et le système de trop-plein.", content: "Canalisations nécessaires pour une piscine : alimentation en eau potable (PEHD ou PER alimentaire), réseau hydraulique de filtration (PVC pression PN10/PN16), canalisation de vidange vers le réseau EP ou le terrain (PVC CR8 Ø110 minimum), et trop-plein raccordé au réseau d'eaux pluviales. Attention : il est interdit de raccorder la vidange de piscine au réseau d'eaux usées (eau chlorée). Nos artisans réalisent l'ensemble du réseau hydraulique de votre piscine." },
  { slug: "canalisation-eau-chaude-bouclage", category: "service", h1: "Bouclage Eau Chaude Sanitaire — Installation et Réparation", metaTitle: "Bouclage Eau Chaude Sanitaire Val d'Oise — Eau Chaude Instantanée", metaDesc: "Installation de bouclage eau chaude sanitaire dans le Val d'Oise. Eau chaude instantanée, économies d'eau. Artisan plombier qualifié.", intro: "Le bouclage d'eau chaude sanitaire (ECS) permet d'obtenir de l'eau chaude instantanément à chaque robinet, sans attendre ni gaspiller.", content: "Le principe : une canalisation de retour relie le point d'eau le plus éloigné au ballon d'eau chaude. Une pompe de circulation fait circuler l'eau en permanence (ou sur programmation horaire) dans cette boucle. Résultat : l'eau chaude arrive en moins de 5 secondes à chaque robinet. Économie moyenne : 15 000 litres d'eau par an pour un foyer de 4 personnes. Nos artisans installent le bouclage ECS avec pompe de recirculation, calorifugeage des tuyaux et programmation horaire." },
  // ═══ LOT 3 — DERNIÈRES PAGES POUR ATTEINDRE 100 ═══
  { slug: "remplacement-canalisation-sannois", category: "ville", h1: "Remplacement de Canalisation à Sannois (95110)", metaTitle: "Remplacement Canalisation Sannois (95110) — Butte Témoin", metaDesc: "Remplacement de canalisation à Sannois (95110). Butte témoin, terrain en pente, canalisations sous pression gravitaire. Artisan local.", intro: "Sannois, sur sa butte témoin, présente des contraintes de terrain en pente qui sollicitent fortement les canalisations.", content: "La topographie pentue de Sannois (dénivelé de plus de 100 m entre le haut et le bas de la butte) crée des pressions gravitaires importantes dans les canalisations. Cela accélère l'usure des joints et peut provoquer des déboîtements. Nos artisans utilisent des raccords verrouillés et des butées en béton pour sécuriser les canalisations en pente." },
  { slug: "reparation-fuite-deuil-la-barre", category: "ville", h1: "Réparation de Fuite à Deuil-la-Barre (95170)", metaTitle: "Réparation Fuite Deuil-la-Barre (95170) — Vallée de Montmorency", metaDesc: "Fuite canalisation à Deuil-la-Barre (95170). Quartier résidentiel vallée de Montmorency. Détection et réparation rapide.", intro: "Deuil-la-Barre, zone résidentielle de la vallée de Montmorency, possède des canalisations pavillonnaires à entretenir régulièrement.", content: "Les canalisations des quartiers pavillonnaires de Deuil-la-Barre datent pour la plupart des années 60-80. Les mouvements du terrain argileux fragilisent les joints et raccords, provoquant des fuites lentes difficiles à détecter. Nos techniciens utilisent l'écoute acoustique pour localiser ces micro-fuites sans casser votre terrasse ou votre allée." },
  { slug: "canalisation-urgence-domont", category: "ville", h1: "Canalisation en Urgence à Domont (95330)", metaTitle: "Canalisation Urgence Domont (95330) — Forêt de Montmorency", metaDesc: "Urgence canalisation à Domont (95330) ? Lisière forêt Montmorency, terrain calcaire et argileux. Intervention sous 1h.", intro: "Domont, en lisière de la forêt de Montmorency, cumule terrain calcaire et problématiques de racines intrusives.", content: "La proximité de la forêt expose les canalisations aux racines des grands arbres qui s'infiltrent par les moindres fissures. Le terrain mixte calcaire-argileux de Domont ajoute des contraintes de dépôt calcaire et de mouvement de sol. Nos artisans proposent un traitement complet : retrait des racines, nettoyage anti-calcaire, et renforcement par chemisage si nécessaire." },
  { slug: "diagnostic-camera-saint-ouen-laumone", category: "ville", h1: "Diagnostic Caméra à Saint-Ouen-l'Aumône (95310)", metaTitle: "Diagnostic Caméra Saint-Ouen-l'Aumône (95310) — Bord de l'Oise", metaDesc: "Inspection caméra canalisation à Saint-Ouen-l'Aumône (95310). Bord de l'Oise, réseaux mixtes industriels et résidentiels.", intro: "Saint-Ouen-l'Aumône, en bord de l'Oise, mêle zones résidentielles et d'activités avec des réseaux de canalisations diversifiés.", content: "Les zones d'activités de Saint-Ouen-l'Aumône (ZA du Vert-Galant, ZA des Béthunes) ont des canalisations industrielles de gros diamètre nécessitant un suivi par inspection caméra. Les quartiers résidentiels ont des réseaux plus classiques. Notre caméra s'adapte aux deux types de réseau, du Ø50 mm au Ø400 mm." },
  { slug: "remplacement-canalisation-beaumont-sur-oise", category: "ville", h1: "Remplacement de Canalisation à Beaumont-sur-Oise (95260)", metaTitle: "Remplacement Canalisation Beaumont-sur-Oise (95260)", metaDesc: "Remplacement de canalisation à Beaumont-sur-Oise (95260). Bord de l'Oise, centre historique. Artisan canalisateur local.", intro: "Beaumont-sur-Oise, petite ville au bord de l'Oise, possède un centre historique avec des canalisations anciennes à remplacer.", content: "Le centre ancien de Beaumont-sur-Oise conserve des canalisations en grès et fonte centenaires. La proximité de l'Oise et les nappes hautes compliquent les interventions de terrassement. Nos artisans maîtrisent les travaux en zone humide avec pompage et blindage étanche." },
  { slug: "plombier-canalisateur-val-doise", category: "service", h1: "Plombier Canalisateur dans le Val d'Oise — Artisan Certifié", metaTitle: "Plombier Canalisateur Val d'Oise (95) — Consortium Artisans Certifiés", metaDesc: "Cherchez un plombier canalisateur dans le Val d'Oise ? Consortium d'artisans locaux certifiés. Intervention sous 1h, garantie décennale.", intro: "Un plombier canalisateur est un artisan spécialisé dans les travaux sur les réseaux d'évacuation et d'alimentation en eau.", content: "À la différence d'un plombier sanitaire qui intervient sur la robinetterie et les appareils, le canalisateur est spécialisé dans les réseaux enterrés : terrassement, pose de canalisations, raccordement au réseau public, essais d'étanchéité. Notre consortium regroupe des artisans canalisateurs certifiés, implantés dans le Val d'Oise depuis plus de 15 ans, disposant de tout le matériel professionnel nécessaire (mini-pelle, camion hydrocureur, caméra d'inspection)." },
  { slug: "artisan-canalisation-urgence-95", category: "service", h1: "Artisan Canalisation Urgence dans le 95", metaTitle: "Artisan Canalisation Urgence 95 — Intervention Immédiate Val d'Oise", metaDesc: "Artisan canalisateur en urgence dans le 95 (Val d'Oise). Intervention sous 1h, 7j/7. Fuite, bouchon, remplacement. Devis gratuit.", intro: "En cas d'urgence canalisation dans le 95, nos artisans locaux se déplacent en moins d'une heure chez vous.", content: "Notre consortium d'artisans canalisateurs couvre l'ensemble du département 95 : d'Argenteuil à L'Isle-Adam, de Cergy à Sarcelles. Chaque artisan est basé dans le Val d'Oise et connaît les spécificités locales (types de sol, réseaux anciens, contraintes d'accessibilité). Urgences traitées : fuite active avec dégât des eaux, refoulement d'eaux usées, canalisation cassée, WC bouchés. Disponible 7j/7 de 8h à 20h, sans majoration le week-end." },
  { slug: "devis-gratuit-canalisation-95", category: "prix", h1: "Devis Gratuit Canalisation Val d'Oise (95)", metaTitle: "Devis Gratuit Canalisation 95 — Remplacement, Réparation, Diagnostic", metaDesc: "Devis gratuit pour tous travaux de canalisation dans le Val d'Oise (95). Sur place ou par téléphone. Réponse sous 30 min. Sans engagement.", intro: "Tous nos devis sont gratuits, détaillés poste par poste, et sans aucun engagement de votre part.", content: "Comment obtenir votre devis : appelez-nous au 06 06 06 06 06 ou remplissez le formulaire en ligne. Un artisan vous rappelle sous 30 minutes. Pour les travaux importants (remplacement de canalisation), une visite sur place gratuite est systématiquement proposée avec diagnostic caméra si nécessaire. Le devis détaille chaque poste : terrassement (ml), fourniture (matériau, diamètre), main d'œuvre (heures), remise en état (type de surface). Aucune surprise sur la facture finale." },
  { slug: "intervention-rapide-canalisation-95", category: "urgence", h1: "Intervention Rapide Canalisation — Moins d'1h dans le 95", metaTitle: "Intervention Rapide Canalisation 95 — Sous 1h dans le Val d'Oise", metaDesc: "Intervention canalisation en moins d'1h dans tout le Val d'Oise (95). Artisans locaux répartis sur le département. 7j/7.", intro: "Nos artisans sont répartis stratégiquement dans le Val d'Oise pour garantir un temps d'intervention inférieur à 1 heure.", content: "Répartition de nos artisans : zone sud (Argenteuil, Bezons, Franconville, Ermont) — temps moyen 30 min. Zone centre (Cergy, Pontoise, Osny) — temps moyen 35 min. Zone nord (Goussainville, Sarcelles, Villiers-le-Bel) — temps moyen 40 min. Zone est (Montmorency, Enghien, Soisy) — temps moyen 25 min. Le dispatching est fait par téléphone en moins de 2 minutes : l'artisan le plus proche de chez vous est mobilisé immédiatement." },
  { slug: "canalisation-fonte-vs-pvc", category: "materiau", h1: "Canalisation Fonte vs PVC — Comparatif et Choix", metaTitle: "Fonte vs PVC Canalisation — Avantages, Inconvénients, Prix Comparés", metaDesc: "Fonte ou PVC pour votre canalisation ? Comparatif complet : durée de vie, prix, résistance, facilité de pose. Guide pour bien choisir.", intro: "Le choix entre fonte et PVC dépend de l'usage (assainissement, eau potable), des contraintes du terrain et du budget.", content: "Fonte ductile : très résistante mécaniquement (passage sous voirie), insonore (moins de bruit d'écoulement), mais plus chère (3 à 5x le prix du PVC), plus lourde (manutention difficile), et sujette à la corrosion interne après 50 ans. PVC : léger, facile à poser et à couper, résistant à la corrosion, économique, mais plus fragile mécaniquement (écrasement possible), et plus bruyant. Recommandation : PVC CR8/CR16 pour l'assainissement enterré classique, fonte pour les passages sous voirie ou les colonnes d'immeuble (insonorisation)." },
  { slug: "contrat-entretien-canalisation", category: "service", h1: "Contrat d'Entretien Canalisation — Tranquillité et Économie", metaTitle: "Contrat Entretien Canalisation Val d'Oise — Curage Annuel + Caméra", metaDesc: "Contrat d'entretien canalisation dans le Val d'Oise. Curage annuel + inspection caméra. Tarif préférentiel, priorité d'intervention.", intro: "Un contrat d'entretien annuel pour vos canalisations coûte bien moins cher que les réparations d'urgence qu'il permet d'éviter.", content: "Notre contrat d'entretien comprend : un curage par hydrocurage annuel de votre réseau d'évacuation, une inspection caméra annuelle avec rapport, un traitement anti-racines si nécessaire, et une priorité d'intervention en cas d'urgence (délai réduit à 30 min au lieu d'1h). Tarif préférentiel : 30 à 40% de réduction sur les tarifs unitaires. Idéal pour les copropriétés, les maisons anciennes et les propriétés proches de la forêt (risque racines)." },
  { slug: "canalisation-renovation-energetique", category: "service", h1: "Canalisation et Rénovation Énergétique — Profitez des Travaux", metaTitle: "Canalisation + Rénovation Énergétique Val d'Oise — Profitez du Chantier", metaDesc: "Rénovation énergétique en cours ? Profitez du chantier pour remplacer vos canalisations. Économies sur le terrassement. Val d'Oise.", intro: "Si vous réalisez des travaux de rénovation énergétique (isolation des sols, drainage), c'est le moment idéal pour remplacer vos canalisations à moindre coût.", content: "Quand le terrassement est déjà prévu pour d'autres travaux (drainage périphérique, isolation des fondations, création de vide sanitaire), le surcoût pour remplacer les canalisations est réduit de 30 à 50% car le poste terrassement est mutualisé. Nos artisans coordonnent leurs interventions avec votre entreprise de rénovation pour minimiser la durée du chantier et optimiser les coûts. Pensez-y avant de refermer les tranchées !" },
  { slug: "remplacement-branchement-eau-potable", category: "service", h1: "Remplacement de Branchement d'Eau Potable — Compteur à Maison", metaTitle: "Remplacement Branchement Eau Potable Val d'Oise — Compteur à Maison", metaDesc: "Remplacement du branchement d'eau potable (du compteur à la maison) dans le Val d'Oise. Plomb, cuivre, PEHD. Devis gratuit.", intro: "Le branchement d'eau potable (canalisation entre le compteur et votre habitation) est sous votre responsabilité en tant que propriétaire.", content: "Si votre branchement est en plomb (maisons d'avant 1950), le remplacement est fortement recommandé pour des raisons sanitaires. Si votre branchement est en cuivre ancien ou en PER dégradé, le remplacement par du PEHD alimentaire (bande bleue, NF EN 12201) garantit une durée de vie de 50+ ans. Nos artisans réalisent le remplacement complet : fermeture au compteur, tranchée, pose du nouveau branchement, raccordement et essai de pression. Démarche auprès du service des eaux gérée." },
];

export function getLongtailBySlug(slug: string): LongTail | undefined {
  return longtails.find((l) => l.slug === slug);
}

export function getAllLongtailSlugs(): string[] {
  return longtails.map((l) => l.slug);
}
